interface Circle {
  kind: 'circle';
  radius: number;
}

interface Rectangle {
  kind: 'rectangle';
  width: number;
  height: number;
}

type Shape = Circle | Rectangle;

// User-defined type guard function
function isCircle(shape: Shape): shape is Circle {
  return shape.kind === 'circle' && typeof shape.radius === 'number';
}

function calculateArea(shape: Shape): number {
  if (isCircle(shape)) {
    // TypeScript knows 'shape' is Circle here
    return Math.PI * shape.radius * shape.radius;
  } else {
    // Here, TypeScript infers 'shape' is Rectangle
    return shape.width * shape.height;
  }
}

def convert_to_int(value):
    try:
        return int(value)
    except TypeError:
        print(f"TypeError: Cannot convert {type(value)} to int.")
    except ValueError:
        print(f"ValueError: The value '{value}' is not a valid integer.")

# Test the function
convert_to_int([1, 2, 3])  # TypeError
convert_to_int("hello")    # ValueError
convert_to_int("123")      # 123
